// Devuelve ofertas. Dos modos:
//
//   ?id=<uuid>                  → devuelve UNA oferta concreta (acceder a ella).
//   sin id                      → listado con filtros opcionales:
//     ?cliente=<texto>           contains, case-insensitive, sobre sociedad y nombre
//     ?cif=<texto>               match exacto sobre cliente_cif (uppercase)
//     ?comercial=<nombre>        match exacto
//     ?estado=<estado>           borrador|enviada|aceptada|rechazada|caducada
//     ?plan=<plan>               lite|basic|pro
//     ?billing=<modo>            annual|monthly
//     ?incluir_archivadas=1      incluye soft-deleted al final del orden
//
// Orden: vivos primero; dentro de vivos por created_at desc.
const wh = $('Webhook GET Ofertas').first().json || {};
const q = wh.query || wh.params || {};
const verArch = String(q.incluir_archivadas || '') === '1';
const raw = ($input.all() || [])
  .map(i => i.json)
  .filter(x => x && x.id && (verArch || !x.deleted_at));

// Modo acceso directo: ?id=<uuid> devuelve una sola oferta.
if (q.id) {
  const one = raw.find(o => String(o.id) === String(q.id));
  return [{ json: { oferta: one || null } }];
}

let out = raw;
if (q.cliente) {
  const needle = String(q.cliente).toLowerCase();
  out = out.filter(o =>
    String(o.cliente_sociedad || '').toLowerCase().includes(needle) ||
    String(o.cliente_nombre   || '').toLowerCase().includes(needle)
  );
}
if (q.cif)        out = out.filter(o => String(o.cliente_cif || '').toUpperCase() === String(q.cif).toUpperCase());
if (q.comercial)  out = out.filter(o => o.comercial === q.comercial);
if (q.estado)     out = out.filter(o => o.estado    === q.estado);
if (q.plan)       out = out.filter(o => o.plan      === q.plan);
if (q.billing)    out = out.filter(o => o.billing   === q.billing);

// Vivos primero, archivados al final. Dentro: por created_at desc.
out.sort((a, b) => {
  const ax = a.deleted_at ? 1 : 0;
  const bx = b.deleted_at ? 1 : 0;
  if (ax !== bx) return ax - bx;
  const da = a.created_at ? new Date(a.created_at).getTime() : 0;
  const db = b.created_at ? new Date(b.created_at).getTime() : 0;
  return db - da;
});

// Agregados útiles para la UI (sólo vivos).
const totales = out.filter(o => !o.deleted_at).reduce((acc, o) => {
  acc.n += 1;
  acc.final_amount   += Number(o.final_amount)   || 0;
  acc.annual_subtotal += Number(o.annual_subtotal) || 0;
  return acc;
}, { n: 0, final_amount: 0, annual_subtotal: 0 });

return [{ json: { ofertas: out, totales } }];

// Acciones soportadas:
//   create          → alta de oferta (estado por defecto 'borrador').
//   update          → edición libre de campos.
//   archivar        → soft-delete (deleted_at=now).
//   reactivar       → deshace archivar.
//   cambiar_estado  → cambia 'estado' (borrador|enviada|aceptada|rechazada|caducada).
//   vincular_ficha  → setea solicitud_ficha_id cuando la oferta se materializa.
const raw = $input.first().json || {};
const b = (raw.body && typeof raw.body === 'object') ? raw.body : raw;
const action = String(b.action || '').toLowerCase();
const o = b.oferta || {};
const now = new Date().toISOString();
const errores = [];

const VALID    = ['create', 'update', 'archivar', 'reactivar', 'cambiar_estado', 'vincular_ficha'];
const BILLING  = ['annual', 'monthly'];
const PLANES   = ['lite', 'basic', 'pro'];
const IMPLS    = ['grupal', 'personalizada'];
const ESTADOS  = ['borrador', 'enviada', 'aceptada', 'rechazada', 'caducada'];
const TIPOS    = ['lite', 'planes', 'corporate', 'corporate_cp', 'corp_cocina'];

function esUuid(v){ return /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(String(v||'')); }
function num(v, nombre, min, max){
  if (v === undefined || v === null || v === '') return undefined;
  const n = +v;
  if (!Number.isFinite(n)) { errores.push(nombre + ' debe ser número'); return undefined; }
  if (n < min || n > max)  { errores.push(nombre + ' fuera de rango (' + min + '..' + max + ')'); return undefined; }
  return n;
}

if (!VALID.includes(action)) errores.push('action inválida: ' + action);
if (action !== 'create' && !o.id) errores.push('id obligatorio para ' + action);
if (o.id && !esUuid(o.id)) errores.push('id no es un UUID válido');

let out = {};

if (action === 'create') {
  if (!o.billing || !BILLING.includes(o.billing)) errores.push('billing debe ser annual|monthly');
  if (!o.plan    || !PLANES.includes(o.plan))    errores.push('plan debe ser lite|basic|pro');
  if (o.impl && !IMPLS.includes(o.impl))         errores.push('impl debe ser grupal|personalizada');
  if (o.estado   && !ESTADOS.includes(o.estado)) errores.push('estado inválido');
  if (o.tipo_plan && !TIPOS.includes(o.tipo_plan)) errores.push('tipo_plan inválido');
  if (o.cliente_email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(o.cliente_email)) errores.push('cliente_email no válido');
  if (o.solicitud_ficha_id && !esUuid(o.solicitud_ficha_id)) errores.push('solicitud_ficha_id no es UUID');
  const locales = num(o.locales, 'locales', 1, 999);
  // UUID v4 generado aquí para que PostgREST tenga PK explícita
  // (mismo truco que en 22-presupuestos.json).
  const _uuid = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c){ const r = Math.random()*16|0; return (c==='x'?r:(r&0x3)|0x8).toString(16); });
  out = {
    id: _uuid,
    billing: o.billing,
    plan: o.plan,
    locales: locales !== undefined ? locales : 1,
    addons: (o.addons && typeof o.addons === 'object') ? o.addons : {},
    impl: o.impl || null,
    cliente_sociedad: o.cliente_sociedad ? String(o.cliente_sociedad).trim() : null,
    cliente_cif:      o.cliente_cif      ? String(o.cliente_cif).trim().toUpperCase() : null,
    cliente_nombre:   o.cliente_nombre   ? String(o.cliente_nombre).trim() : null,
    cliente_email:    o.cliente_email    ? String(o.cliente_email).trim() : null,
    comercial:        o.comercial        ? String(o.comercial).trim() : null,
    tipo_plan:        o.tipo_plan || null,
    monthly_total:   num(o.monthly_total,   'monthly_total',   0, 99999999.99) || 0,
    annual_subtotal: num(o.annual_subtotal, 'annual_subtotal', 0, 99999999.99) || 0,
    onetime_total:   num(o.onetime_total,   'onetime_total',   0, 99999999.99) || 0,
    bonus_val:       num(o.bonus_val,       'bonus_val',       0, 99999999.99) || 0,
    full_val:        num(o.full_val,        'full_val',        0, 99999999.99) || 0,
    final_amount:    num(o.final_amount,    'final_amount',    0, 99999999.99) || 0,
    estado:          o.estado || 'borrador',
    solicitud_ficha_id: o.solicitud_ficha_id || null,
    notas:      o.notas      != null ? String(o.notas) : null,
    created_by: o.created_by != null ? String(o.created_by) : null,
    created_at: now,
    updated_at: now
  };
} else if (action === 'update') {
  out.id = o.id;
  if (o.billing !== undefined) {
    if (!BILLING.includes(o.billing)) errores.push('billing inválido');
    else out.billing = o.billing;
  }
  if (o.plan !== undefined) {
    if (!PLANES.includes(o.plan)) errores.push('plan inválido');
    else out.plan = o.plan;
  }
  if (o.impl !== undefined) {
    if (o.impl !== null && !IMPLS.includes(o.impl)) errores.push('impl inválido');
    else out.impl = o.impl;
  }
  if (o.tipo_plan !== undefined) {
    if (o.tipo_plan !== null && !TIPOS.includes(o.tipo_plan)) errores.push('tipo_plan inválido');
    else out.tipo_plan = o.tipo_plan;
  }
  if (o.locales !== undefined) { const n = num(o.locales, 'locales', 1, 999); if (n !== undefined) out.locales = n; }
  if (o.addons  !== undefined) out.addons = (o.addons && typeof o.addons === 'object') ? o.addons : {};
  ['cliente_sociedad','cliente_cif','cliente_nombre','cliente_email','comercial','notas','created_by'].forEach(k => {
    if (o[k] !== undefined) out[k] = o[k] == null ? null : (k === 'cliente_cif' ? String(o[k]).trim().toUpperCase() : String(o[k]).trim());
  });
  if (out.cliente_email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(out.cliente_email)) errores.push('cliente_email no válido');
  ['monthly_total','annual_subtotal','onetime_total','bonus_val','full_val','final_amount'].forEach(k => {
    if (o[k] !== undefined) { const n = num(o[k], k, 0, 99999999.99); if (n !== undefined) out[k] = n; }
  });
  if (o.estado !== undefined) {
    if (!ESTADOS.includes(o.estado)) errores.push('estado inválido');
    else out.estado = o.estado;
  }
  if (o.solicitud_ficha_id !== undefined) {
    if (o.solicitud_ficha_id !== null && !esUuid(o.solicitud_ficha_id)) errores.push('solicitud_ficha_id no es UUID');
    else out.solicitud_ficha_id = o.solicitud_ficha_id;
  }
  out.updated_at = now;
} else if (action === 'archivar') {
  out = { id: o.id, deleted_at: now, updated_at: now };
} else if (action === 'reactivar') {
  out = { id: o.id, deleted_at: null, updated_at: now };
} else if (action === 'cambiar_estado') {
  if (!ESTADOS.includes(o.estado)) errores.push('estado inválido');
  out = { id: o.id, estado: o.estado, updated_at: now };
} else if (action === 'vincular_ficha') {
  if (!esUuid(o.solicitud_ficha_id)) errores.push('solicitud_ficha_id obligatorio y UUID');
  out = { id: o.id, solicitud_ficha_id: o.solicitud_ficha_id, updated_at: now };
}

Object.keys(out).forEach(k => { if (out[k] === undefined) delete out[k]; });

if (errores.length > 0) {
  return [{ json: { __error: true, __errores: errores, __action: action } }];
}
const _method = (action === 'create') ? 'POST' : 'PATCH';
const _qs     = (action === 'create') ? 'on_conflict=id' : ('id=eq.' + encodeURIComponent(o.id || ''));
return [{ json: Object.assign({}, out, { __method: _method, __qs: _qs }) }];

// Normaliza la salida PostgREST al shape único del frontend:
//   { success, oferta, errores }
const prep = $('Preparar').first().json || {};
if (prep.__error) {
  return [{ json: { success: false, oferta: null, errores: prep.__errores || ['validación falló'] } }];
}
const items = $input.all() || [];
const errores = [];
let rows = [];
for (const it of items) {
  const j = it.json; if (!j) continue;
  if (Array.isArray(j)) { rows = rows.concat(j); continue; }
  if (j.code && j.message && !j.id) { errores.push(j.message + (j.details ? ' (' + j.details + ')' : '')); continue; }
  if (j.error) { errores.push(String(j.error.message || j.error)); continue; }
  if (j.id) rows.push(j);
  if (Array.isArray(j.data)) rows = rows.concat(j.data);
}
if (rows.length === 0 && errores.length === 0) errores.push('PostgREST devolvió 0 filas');
return [{ json: { success: rows.length > 0, oferta: rows[0] || null, errores } }];
